
import { outputValueStatistics } from "@/server/http/api/system";
import {
  defineComponent,
  nextTick,
  onMounted,
  getCurrentInstance,
  ref,
  watch,
  reactive,
} from "vue";

export default defineComponent({
  props: ["optionsArr", "active"],
  setup(props) {
    const { proxy } = getCurrentInstance() as any;
    let myChart: any;
    let options: any = reactive({
      time: [],
      values: [],
    });
    watch(
      () => props.active,
      (newVal) => {
        outputValueStatistics(props.active).then((res: any) => {
          if (res.data.code === 200) {
            options.time = [];
            options.values = [];
            res.data.data.forEach((item: any) => {
              options.time.push(item.label);
              options.values.push(item.value);
            });
            myChart.setOption({
              // title: {
              //   text: "统计",
              // },
              tooltip: {
                trigger: "axis",
              },
              legend: {
                data: ["产值"],
              },
              grid: {
                left: "3%",
                right: "4%",
                bottom: "3%",
                containLabel: true,
              },
              toolbox: {
                feature: {
                  saveAsImage: {},
                },
              },
              xAxis: {
                type: "category",
                boundaryGap: false,
                data: options.time,
              },
              yAxis: {
                type: "value",
              },
              series: [
                {
                  name: "产值",
                  type: "line",
                  stack: "总量",
                  data: options.values,
                },
              ],
            });
          }
        });
      },
      {
        immediate: true,
      }
    );

    onMounted(() => {
      const option = {
        // title: {
        //   text: "统计",
        // },
        tooltip: {
          trigger: "axis",
        },
        legend: {
          data: ["产值"],
        },
        grid: {
          left: "3%",
          right: "4%",
          bottom: "3%",
          containLabel: true,
        },
        toolbox: {
          feature: {
            saveAsImage: {},
          },
        },
        xAxis: {
          type: "category",
          boundaryGap: false,
          data: ["周一", "周二", "周三", "周四", "周五", "周六", "周日"],
        },
        yAxis: {
          type: "value",
        },
        series: [
          {
            name: "产值",
            type: "line",
            stack: "总量",
            data: [0, 0, 0, 0, 0, 0, 0],
          },
          //   {
          //     name: "联盟广告",
          //     type: "line",
          //     stack: "总量",
          //     data: [220, 182, 191, 234, 290, 330, 310],
          //   },
          //   {
          //     name: "视频广告",
          //     type: "line",
          //     stack: "总量",
          //     data: [150, 232, 201, 154, 190, 330, 410],
          //   },
          //   {
          //     name: "直接访问",
          //     type: "line",
          //     stack: "总量",
          //     data: [320, 332, 301, 334, 390, 330, 320],
          //   },
          //   {
          //     name: "搜索引擎",
          //     type: "line",
          //     stack: "总量",
          //     data: [820, 932, 901, 934, 1290, 1330, 1320],
          //   },
        ],
      };
      nextTick(() => {
        const chartDom = <HTMLElement>document.getElementById("main");
        myChart = proxy.$echarts.init(chartDom);
        myChart.setOption(option);

        window.onresize = function () {
          myChart.resize();
        };
      });
    });

    return {
      options,
    };
  },
});
